1	import { useState, useEffect, useCallback } from "react";
2	import SuccessOverlay from "@/components/ui/SuccessOverlay";
3	import { supabase } from "@/integrations/supabase/client";
4	import { Button } from "@/components/ui/button";
5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { Textarea } from "@/components/ui/textarea";
8	import {
9	  Dialog,
10	  DialogContent,
11	  DialogHeader,
12	  DialogTitle,
13	} from "@/components/ui/dialog";
14	import {
15	  Select,
16	  SelectContent,
17	  SelectItem,
18	  SelectTrigger,
19	  SelectValue,
20	} from "@/components/ui/select";
21	import { Plus, Trash2, Receipt, Building2, CheckCircle2, Settings } from "lucide-react";
22	import { Link } from "react-router-dom";
23	import { toast } from "sonner";
24	
25	interface InvoiceItem {
26	  id?: string;
27	  description: string;
28	  quantity: string;
29	  unit_price: string;
30	  total: number;
31	}
32	
33	interface BusinessSettings {
34	  business_name: string;
35	  business_email: string;
36	  business_phone: string;
37	  business_address: string;
38	  logo_url: string;
39	  tax_id: string;
40	  default_currency: string;
41	  default_tax_rate: number;
42	  default_payment_terms: string;
43	  bank_name?: string;
44	  bank_account_name?: string;
45	  bank_account_number?: string;
46	  mpesa_till_number?: string;
47	}
48	
49	interface CreateInvoiceDialogProps {
50	  open: boolean;
51	  onOpenChange: (open: boolean) => void;
52	  editingInvoice?: any;
53	  onSuccess: () => void;
54	  onCreated?: (id: string) => void;
55	  kiraContext?: Record<string, unknown> | null;
56	  businessSettings?: BusinessSettings | null;
57	}
58	
59	const currencies = [
60	  { code: "KES", name: "Kenyan Shilling" },
61	  { code: "USD", name: "US Dollar" },
62	  { code: "EUR", name: "Euro" },
63	  { code: "GBP", name: "British Pound" },
64	  { code: "NGN", name: "Nigerian Naira" },
65	  { code: "ZAR", name: "South African Rand" },
66	  { code: "GHS", name: "Ghanaian Cedi" },
67	  { code: "TZS", name: "Tanzanian Shilling" },
68	  { code: "UGX", name: "Ugandan Shilling" },
69	];
70	
71	const CreateInvoiceDialog = ({
72	  open,
73	  onOpenChange,
74	  editingInvoice,
75	  onSuccess,
76	  onCreated,
77	  kiraContext,
78	}: CreateInvoiceDialogProps) => {
79	  const [loading, setLoading] = useState(false);
80	  const [showSuccess, setShowSuccess] = useState(false);
81	  const [invoiceNumber, setInvoiceNumber] = useState("");
82	  const [clientName, setClientName] = useState("");
83	  const [clientEmail, setClientEmail] = useState("");
84	  const [clientAddress, setClientAddress] = useState("");
85	  const [issueDate, setIssueDate] = useState(new Date().toISOString().split("T")[0]);
86	  const [dueDate, setDueDate] = useState("");
87	  const [currency, setCurrency] = useState("KES");
88	  const [taxRate, setTaxRate] = useState<string>("");
89	  const [discountAmount, setDiscountAmount] = useState<string>("");
90	  const [notes, setNotes] = useState("");
91	  const [terms, setTerms] = useState("Payment is due within 30 days of invoice date.");
92	  const [items, setItems] = useState<InvoiceItem[]>([
93	    { description: "", quantity: "", unit_price: "", total: 0 },
94	  ]);
95	  const [loadedSettings, setLoadedSettings] = useState<BusinessSettings | null>(null);
96	  const [settingsLoading, setSettingsLoading] = useState(false);
97	
98	  // Effect 1 — synchronous form reset the moment the dialog opens
99	  useEffect(() => {
100	    if (!open) return;
101	    if (editingInvoice) {
102	      setInvoiceNumber(editingInvoice.invoice_number);
103	      setClientName(editingInvoice.client_name);
104	      setClientEmail(editingInvoice.client_email || "");
105	      setClientAddress(editingInvoice.client_address || "");
106	      setIssueDate(editingInvoice.issue_date);
107	      setDueDate(editingInvoice.due_date);
108	      setCurrency(editingInvoice.currency);
109	      setTaxRate(editingInvoice.tax_rate ? String(editingInvoice.tax_rate) : "");
110	      setDiscountAmount(editingInvoice.discount_amount ? String(editingInvoice.discount_amount) : "");
111	      setNotes(editingInvoice.notes || "");
112	      setTerms(editingInvoice.terms || "");
113	      fetchItems(editingInvoice.id);
114	    } else {
115	      // Immediate sync reset with defaults (settings will override below)
116	      generateInvoiceNumber();
117	      setClientName(""); setClientEmail(""); setClientAddress("");
118	      setIssueDate(new Date().toISOString().split("T")[0]);
119	      setDueDate(""); setDiscountAmount(""); setNotes("");
120	      setCurrency("KES");
121	      setTaxRate("");
122	      setTerms("Payment is due within 30 days of invoice date.");
123	      setItems([{ description: "", quantity: "", unit_price: "", total: 0 }]);
124	      setLoadedSettings(null);
125	
126	      // Kira context
127	      if (kiraContext) {
128	        if (kiraContext.client_name) setClientName(kiraContext.client_name as string);
129	        if (kiraContext.client_email) setClientEmail(kiraContext.client_email as string);
130	        if (kiraContext.currency) setCurrency(kiraContext.currency as string);
131	        if (kiraContext.notes) setNotes(kiraContext.notes as string);
132	        if (Array.isArray(kiraContext.items) && kiraContext.items.length > 0) {
133	          setItems(
134	            (kiraContext.items as Array<{ description: string; quantity: number; unit_price: number }>).map(
135	              (item) => ({
136	                description: item.description || "",
137	                quantity: String(item.quantity || 1),
138	                unit_price: String(item.unit_price || 0),
139	                total: (item.quantity || 1) * (item.unit_price || 0),
140	              })
141	            )
142	          );
143	        }
144	      }
145	    }
146	  }, [open, editingInvoice, kiraContext]);
147	
148	  // Effect 2 — async settings fetch, runs independently, overrides defaults when ready
149	  useEffect(() => {
150	    if (!open || editingInvoice) return;
151	
152	    let cancelled = false;
153	    setSettingsLoading(true);
154	
155	    (async () => {
156	      try {
157	        const { data: { session } } = await supabase.auth.getSession();
158	        if (cancelled || !session) return;
159	
160	        const { data: bs } = await supabase
161	          .from("business_settings")
162	          .select("*")
163	          .eq("user_id", session.user.id)
164	          .single();
165	
166	        if (cancelled) return;
167	
168	        if (bs) {
169	          setLoadedSettings(bs as BusinessSettings);
170	          if (bs.default_currency)     setCurrency(bs.default_currency);
171	          if (bs.default_tax_rate)     setTaxRate(String(bs.default_tax_rate));
172	          if (bs.default_payment_terms) setTerms(bs.default_payment_terms);
173	        } else {
174	          // Fallback: show profile info in the FROM card
175	          const { data: profile } = await supabase
176	            .from("profiles")
177	            .select("display_name, email, avatar_url")
178	            .eq("id", session.user.id)
179	            .single();
180	          if (!cancelled && profile) {
181	            setLoadedSettings({
182	              business_name: profile.display_name || profile.email || "",
183	              business_email: profile.email || "",
184	              business_phone: "", business_address: "",
185	              logo_url: profile.avatar_url || "",
186	              tax_id: "", default_currency: "KES",
187	              default_tax_rate: 0,
188	              default_payment_terms: "Payment is due within 30 days of invoice date.",
189	            });
190	          }
191	        }
192	      } finally {
193	        if (!cancelled) setSettingsLoading(false);
194	      }
195	    })();
196	
197	    return () => { cancelled = true; };
198	  }, [open, editingInvoice]);
199	
200	  const fetchItems = async (invoiceId: string) => {
201	    const { data } = await supabase
202	      .from("invoice_items")
203	      .select("*")
204	      .eq("invoice_id", invoiceId);
205	
206	    if (data && data.length > 0) {
207	      setItems(data.map((item) => ({
208	        id: item.id,
209	        description: item.description,
210	        quantity: String(item.quantity),
211	        unit_price: String(item.unit_price),
212	        total: Number(item.total),
213	      })));
214	    }
215	  };
216	
217	  const generateInvoiceNumber = () => {
218	    const date = new Date();
219	    const year = date.getFullYear();
220	    const month = String(date.getMonth() + 1).padStart(2, "0");
221	    const random = Math.floor(Math.random() * 10000).toString().padStart(4, "0");
222	    setInvoiceNumber(`INV-${year}${month}-${random}`);
223	  };
224	
225	  const initNewInvoice = async () => {
226	    generateInvoiceNumber();
227	
228	    // Fetch business_settings + profile fallback
229	    let bs: BusinessSettings | null = null;
230	    const { data: { session } } = await supabase.auth.getSession();
231	
232	    if (session) {
233	      const { data, error } = await supabase
234	        .from("business_settings")
235	        .select("*")
236	        .eq("user_id", session.user.id)
237	        .single();
238	
239	      if (data) {
240	        bs = data as BusinessSettings;
241	      } else {
242	        // No saved business settings — fall back to profile data
243	        const { data: profile } = await supabase
244	          .from("profiles")
245	          .select("display_name, email, avatar_url")
246	          .eq("id", session.user.id)
247	          .single();
248	
249	        if (profile) {
250	          bs = {
251	            business_name: profile.display_name || "",
252	            business_email: profile.email || "",
253	            business_phone: "",
254	            business_address: "",
255	            logo_url: profile.avatar_url || "",
256	            tax_id: "",
257	            default_currency: "KES",
258	            default_tax_rate: 0,
259	            default_payment_terms: "Payment is due within 30 days of invoice date.",
260	          };
261	          toast.info("Using your profile info. Save your Studio Settings for full autofill.");
262	        }
263	      }
264	    }
265	
266	    setLoadedSettings(bs);
267	
268	    const defaultCurrency = bs?.default_currency || "KES";
269	    const defaultTaxRate  = bs?.default_tax_rate ? String(bs.default_tax_rate) : "";
270	    const defaultTerms    = bs?.default_payment_terms || "Payment is due within 30 days of invoice date.";
271	
272	    setClientName("");
273	    setClientEmail("");
274	    setClientAddress("");
275	    setIssueDate(new Date().toISOString().split("T")[0]);
276	    setDueDate("");
277	    setCurrency(defaultCurrency);
278	    setTaxRate(defaultTaxRate);
279	    setDiscountAmount("");
280	    setNotes("");
281	    setTerms(defaultTerms);
282	    setItems([{ description: "", quantity: "", unit_price: "", total: 0 }]);
283	
284	    // Kira context layered on top of settings defaults
285	    if (kiraContext) {
286	      if (kiraContext.client_name) setClientName(kiraContext.client_name as string);
287	      if (kiraContext.client_email) setClientEmail(kiraContext.client_email as string);
288	      if (kiraContext.currency) setCurrency(kiraContext.currency as string);
289	      if (kiraContext.notes) setNotes(kiraContext.notes as string);
290	      if (Array.isArray(kiraContext.items) && kiraContext.items.length > 0) {
291	        setItems(
292	          (kiraContext.items as Array<{ description: string; quantity: number; unit_price: number }>).map(
293	            (item) => ({
294	              description: item.description || "",
295	              quantity: String(item.quantity || 1),
296	              unit_price: String(item.unit_price || 0),
297	              total: (item.quantity || 1) * (item.unit_price || 0),
298	            })
299	          )
300	        );
301	      }
302	    }
303	  };
304	
305	  const updateItemTotal = (index: number, field: string, value: string) => {
306	    const newItems = [...items];
307	    newItems[index] = { ...newItems[index], [field]: value };
308	    
309	    if (field === "quantity" || field === "unit_price") {
310	      const qty = parseFloat(newItems[index].quantity) || 0;
311	      const price = parseFloat(newItems[index].unit_price) || 0;
312	      newItems[index].total = qty * price;
313	    }
314	    
315	    setItems(newItems);
316	  };
317	
318	  const addItem = () => {
319	    setItems([...items, { description: "", quantity: "", unit_price: "", total: 0 }]);
320	  };
321	
322	  const removeItem = (index: number) => {
323	    if (items.length > 1) {
324	      setItems(items.filter((_, i) => i !== index));
325	    }
326	  };
327	
328	  const calculateTotals = () => {
329	    const subtotal = items.reduce((acc, item) => acc + item.total, 0);
330	    const numTaxRate = parseFloat(taxRate) || 0;
331	    const numDiscount = parseFloat(discountAmount) || 0;
332	    const taxAmount = subtotal * (numTaxRate / 100);
333	    const total = subtotal + taxAmount - numDiscount;
334	    return { subtotal, taxAmount, total };
335	  };
336	
337	  const handleSubmit = async () => {
338	    if (!clientName || !dueDate || items.some((i) => !i.description)) {
339	      toast.error("Please fill in all required fields");
340	      return;
341	    }
342	
343	    setLoading(true);
344	
345	    try {
346	      const { data: { session } } = await supabase.auth.getSession();
347	      if (!session) {
348	        toast.error("Please log in to create invoices");
349	        return;
350	      }
351	
352	      const { subtotal, taxAmount, total } = calculateTotals();
353	
354	      if (editingInvoice) {
355	        // Update invoice
356	        const { error: invoiceError } = await supabase
357	          .from("invoices")
358	          .update({
359	            invoice_number: invoiceNumber,
360	            client_name: clientName,
361	            client_email: clientEmail || null,
362	            client_address: clientAddress || null,
363	            issue_date: issueDate,
364	            due_date: dueDate,
365	            currency,
366	            tax_rate: parseFloat(taxRate) || 0,
367	            tax_amount: taxAmount,
368	            discount_amount: parseFloat(discountAmount) || 0,
369	            subtotal,
370	            total,
371	            notes: notes || null,
372	            terms: terms || null,
373	          })
374	          .eq("id", editingInvoice.id);
375	
376	        if (invoiceError) throw invoiceError;
377	
378	        // Delete existing items and insert new ones
379	        await supabase.from("invoice_items").delete().eq("invoice_id", editingInvoice.id);
380	
381	        const { error: itemsError } = await supabase.from("invoice_items").insert(
382	          items.map((item) => ({
383	            invoice_id: editingInvoice.id,
384	            description: item.description,
385	            quantity: parseFloat(item.quantity) || 0,
386	            unit_price: parseFloat(item.unit_price) || 0,
387	            total: item.total,
388	          }))
389	        );
390	
391	        if (itemsError) throw itemsError;
392	
393	        onSuccess();
394	        onOpenChange(false);
395	        toast.success("Invoice updated");
396	      } else {
397	        const { data: invoice, error: invoiceError } = await supabase
398	          .from("invoices")
399	          .insert({
400	            user_id: session.user.id,
401	            invoice_number: invoiceNumber,
402	            client_name: clientName,
403	            client_email: clientEmail || null,
404	            client_address: clientAddress || null,
405	            issue_date: issueDate,
406	            due_date: dueDate,
407	            currency,
408	            tax_rate: parseFloat(taxRate) || 0,
409	            tax_amount: taxAmount,
410	            discount_amount: parseFloat(discountAmount) || 0,
411	            subtotal,
412	            total,
413	            notes: notes || null,
414	            terms: terms || null,
415	          })
416	          .select()
417	          .single();
418	
419	        if (invoiceError) throw invoiceError;
420	
421	        // Insert items
422	        const { error: itemsError } = await supabase.from("invoice_items").insert(
423	          items.map((item) => ({
424	            invoice_id: invoice.id,
425	            description: item.description,
426	            quantity: parseFloat(item.quantity) || 0,
427	            unit_price: parseFloat(item.unit_price) || 0,
428	            total: item.total,
429	          }))
430	        );
431	
432	        if (itemsError) throw itemsError;
433	
434	        if (invoice?.id) onCreated?.(invoice.id);
435	        onOpenChange(false);
436	        setShowSuccess(true);
437	      }
438	    } catch (error: any) {
439	      toast.error(error.message || "Failed to save invoice");
440	    } finally {
441	      setLoading(false);
442	    }
443	  };
444	
445	  const { subtotal, taxAmount, total } = calculateTotals();
446	
447	  const formatCurrency = (amount: number) => {
448	    return new Intl.NumberFormat("en-KE", {
449	      style: "currency",
450	      currency: currency,
451	    }).format(amount);
452	  };
453	
454	  return (
455	    <>
456	    <SuccessOverlay
457	      show={showSuccess}
458	      title="Invoice Created"
459	      subtitle="Your invoice is ready to send"
460	      onComplete={() => { setShowSuccess(false); onSuccess(); }}
461	    />
462	    <Dialog open={open} onOpenChange={onOpenChange}>
463	      <DialogContent className="w-[calc(100vw-16px)] sm:max-w-2xl lg:max-w-4xl max-h-[90vh] overflow-y-auto">
464	        <DialogHeader>
465	          <DialogTitle className="flex items-center gap-2 font-vollkorn text-xl">
466	            <Receipt className="h-5 w-5 text-bronze" />
467	            {editingInvoice ? "Edit Invoice" : "Create New Invoice"}
468	          </DialogTitle>
469	        </DialogHeader>
470	
471	        <div className="space-y-6">
472	          {/* Invoice Details */}
473	          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
474	            <div>
475	              <Label>Invoice Number</Label>
476	              <Input
477	                value={invoiceNumber}
478	                onChange={(e) => setInvoiceNumber(e.target.value)}
479	                className="mt-1"
480	              />
481	            </div>
482	            <div>
483	              <Label>Issue Date</Label>
484	              <Input
485	                type="date"
486	                value={issueDate}
487	                onChange={(e) => setIssueDate(e.target.value)}
488	                className="mt-1"
489	              />
490	            </div>
491	            <div>
492	              <Label>Due Date *</Label>
493	              <Input
494	                type="date"
495	                value={dueDate}
496	                onChange={(e) => setDueDate(e.target.value)}
497	                className="mt-1"
498	              />
499	            </div>
500	          </div>
501	
502	          {/* From — autofilled from Studio Settings */}
503	          <div className="space-y-3 p-4 rounded-xl border border-border bg-muted/20">
504	            <div className="flex items-center justify-between">
505	              <div className="flex items-center gap-2">
506	                <Building2 className="h-4 w-4 text-bronze" />
507	                <h3 className="font-semibold text-foreground text-sm">From (Your Business)</h3>
508	              </div>
509	              {(loadedSettings?.business_name || loadedSettings?.business_email) ? (
510	                <span className="flex items-center gap-1 text-xs text-emerald-500 font-medium">
511	                  <CheckCircle2 className="h-3.5 w-3.5" />
512	                  Auto-filled from Settings
513	                </span>
514	              ) : (
515	                <Link
516	                  to="/crevia-studio?tab=settings"
517	                  onClick={() => onOpenChange(false)}
518	                  className="flex items-center gap-1 text-xs text-bronze hover:underline font-medium"
519	                >
520	                  <Settings className="h-3.5 w-3.5" />
521	                  Complete your Studio Settings
522	                </Link>
523	              )}
524	            </div>
525	
526	            {(loadedSettings?.business_name || loadedSettings?.business_email) ? (
527	              <div className="space-y-2">
528	                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
529	                  <div className="flex items-start gap-2.5">
530	                    {loadedSettings.logo_url && (
531	                      <img src={loadedSettings.logo_url} alt="logo" className="w-9 h-9 rounded-lg object-cover flex-shrink-0 border border-border" />
532	                    )}
533	                    <div className="min-w-0">
534	                      <p className="font-semibold text-sm text-foreground truncate">{loadedSettings.business_name}</p>
535	                      {loadedSettings.business_email && <p className="text-xs text-muted-foreground truncate">{loadedSettings.business_email}</p>}
536	                      {loadedSettings.business_phone && <p className="text-xs text-muted-foreground">{loadedSettings.business_phone}</p>}
537	                    </div>
538	                  </div>
539	                  <div className="text-xs text-muted-foreground space-y-0.5">
540	                    {loadedSettings.business_address && <p className="whitespace-pre-line">{loadedSettings.business_address}</p>}
541	                    {loadedSettings.tax_id && <p>Tax ID: {loadedSettings.tax_id}</p>}
542	                  </div>
543	                </div>
